export const DECK_STYLE = String.raw`
  @font-face { font-family: "Poppins"; font-weight: 300; font-style: normal; font-display: swap; src: url(data:font/woff2;base64,) format("woff2"); }
  @font-face { font-family: "Poppins"; font-weight: 400; font-style: normal; font-display: swap; src: url(data:font/woff2;base64,) format("woff2"); }
  @font-face { font-family: "Poppins"; font-weight: 500; font-style: normal; font-display: swap; src: url(data:font/woff2;base64,) format("woff2"); }
  @font-face { font-family: "Poppins"; font-weight: 600; font-style: normal; font-display: swap; src: url(data:font/woff2;base64,) format("woff2"); }
  @font-face { font-family: "JetBrains Mono"; font-weight: 400; font-style: normal; font-display: swap; src: url(data:font/woff2;base64,) format("woff2"); }
  @font-face { font-family: "JetBrains Mono"; font-weight: 500; font-style: normal; font-display: swap; src: url(data:font/woff2;base64,) format("woff2"); }

  :root {
    --cream: #faf8f4;
    --black: #111111;
    --charcoal: #1a1a1a;
    --calmgrey: #edebea;
    --signal: #2d5bff;
    --line: color-mix(in srgb, var(--black) 12%, transparent);
    --card: #ffffff;
    --warn-bg: #fff3e6;
    --warn-line: #d98a2b;
    --warn-text: #7a4a0a;
  }
  @media (prefers-color-scheme: dark) {
    :root {
      --cream: #121212;
      --black: #f3f1ec;
      --charcoal: #e7e4dd;
      --calmgrey: #1e1e1e;
      --signal: #6f8cff;
      --line: color-mix(in srgb, #f3f1ec 16%, transparent);
      --card: #191919;
      --warn-bg: #2a2013;
      --warn-line: #a4700f;
      --warn-text: #f0b866;
    }
  }
  :root[data-theme="dark"] {
    --cream: #121212; --black: #f3f1ec; --charcoal: #e7e4dd; --calmgrey: #1e1e1e;
    --signal: #6f8cff; --line: color-mix(in srgb, #f3f1ec 16%, transparent);
    --card: #191919; --warn-bg: #2a2013; --warn-line: #a4700f; --warn-text: #f0b866;
  }
  :root[data-theme="light"] {
    --cream: #faf8f4; --black: #111111; --charcoal: #1a1a1a; --calmgrey: #edebea;
    --signal: #2d5bff; --line: color-mix(in srgb, #111111 12%, transparent);
    --card: #ffffff; --warn-bg: #fff3e6; --warn-line: #d98a2b; --warn-text: #7a4a0a;
  }

  * { box-sizing: border-box; }
  html, body { margin: 0; padding: 0; }
  body {
    background: var(--cream);
    color: var(--black);
    font-family: "Poppins", "Helvetica Neue", Helvetica, Arial, sans-serif;
    font-weight: 400;
    line-height: 1.55;
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
  }
  h1, h2, h3 { font-weight: 500; letter-spacing: -0.015em; text-wrap: balance; margin: 0; }
  p { text-wrap: pretty; margin: 0; }
  a { color: inherit; }
  :focus-visible { outline: 2px solid var(--signal); outline-offset: 3px; border-radius: 2px; }

  .eyebrow {
    font-family: "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, monospace;
    font-size: 0.72rem;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: var(--signal);
    font-weight: 500;
  }

  /* -------- deck shell -------- */
  .deck {
    scroll-snap-type: y proximity;
    height: 100vh;
    overflow-y: auto;
  }
  .slide {
    scroll-snap-align: start;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    justify-content: center;
    padding: clamp(28px, 6vw, 96px) clamp(20px, 7vw, 120px);
    border-bottom: 1px solid var(--line);
    position: relative;
  }
  .slide-inner { max-width: 980px; width: 100%; margin: 0 auto; display: flex; flex-direction: column; gap: 28px; }
  .slide-num {
    position: absolute;
    top: clamp(20px, 4vw, 40px);
    right: clamp(20px, 7vw, 120px);
    font-family: "JetBrains Mono", monospace;
    font-size: 0.72rem;
    color: color-mix(in srgb, var(--black) 45%, transparent);
    letter-spacing: 0.08em;
  }

  /* -------- cover -------- */
  .cover { justify-content: center; }
  .cover .wordmark { font-family: "JetBrains Mono", monospace; font-size: 0.78rem; letter-spacing: 0.18em; text-transform: uppercase; color: color-mix(in srgb, var(--black) 55%, transparent); }
  .cover h1 { font-size: clamp(2.6rem, 2rem + 3.4vw, 4.4rem); line-height: 1.05; max-width: 14ch; }
  .cover .lede { font-size: clamp(1.05rem, 1rem + 0.4vw, 1.25rem); color: color-mix(in srgb, var(--black) 78%, transparent); max-width: 46ch; }
  .cover .meta-row { display: flex; gap: 24px; flex-wrap: wrap; font-size: 0.9rem; color: color-mix(in srgb, var(--black) 62%, transparent); }

  /* -------- badge / callout -------- */
  .callout {
    background: var(--warn-bg);
    border: 1px solid var(--warn-line);
    border-radius: 10px;
    padding: 20px 24px;
    display: flex;
    gap: 16px;
    align-items: flex-start;
  }
  .callout .dot { width: 8px; height: 8px; border-radius: 50%; background: var(--warn-line); margin-top: 8px; flex: none; }
  .callout p { color: var(--warn-text); font-size: 0.98rem; }
  .callout strong { color: var(--warn-text); }

  /* -------- project grid -------- */
  .grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 16px; }
  @media (max-width: 720px) { .grid { grid-template-columns: 1fr; } }
  .card {
    background: var(--card);
    border: 1px solid var(--line);
    border-radius: 12px;
    padding: 22px 24px;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }
  .card-top { display: flex; justify-content: space-between; align-items: flex-start; gap: 10px; }
  .card h3 { font-size: 1.08rem; }
  .status {
    font-family: "JetBrains Mono", monospace;
    font-size: 0.65rem;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    padding: 3px 8px;
    border-radius: 100px;
    white-space: nowrap;
    flex: none;
  }
  .status.draft { background: color-mix(in srgb, var(--signal) 14%, transparent); color: var(--signal); }
  .status.dev { background: var(--warn-bg); color: var(--warn-text); border: 1px solid var(--warn-line); }
  .status.live { background: color-mix(in srgb, #1a9c5b 16%, transparent); color: #1a9c5b; }
  .card p.desc { font-size: 0.92rem; color: color-mix(in srgb, var(--black) 72%, transparent); }
  .card a.link {
    font-family: "JetBrains Mono", monospace;
    font-size: 0.78rem;
    color: var(--signal);
    text-decoration: none;
    border-bottom: 1px solid color-mix(in srgb, var(--signal) 40%, transparent);
    width: fit-content;
    word-break: break-all;
  }
  .card a.link:hover { border-bottom-color: var(--signal); }

  /* -------- project index -------- */
  .toc-list { display: flex; flex-direction: column; border-top: 1px solid var(--line); }
  .toc-row {
    display: flex; justify-content: space-between; align-items: center; gap: 16px;
    padding: 15px 0; border-bottom: 1px solid var(--line);
  }
  .toc-row .index { font-family: "JetBrains Mono", monospace; font-size: 0.78rem; color: color-mix(in srgb, var(--black) 40%, transparent); width: 24px; flex: none; }
  .toc-row .name { font-weight: 500; font-size: 1.05rem; flex: 1; }
  .toc-row .right { display: flex; align-items: center; gap: 14px; flex: none; }
  .toc-row .arrow { color: color-mix(in srgb, var(--black) 35%, transparent); font-family: "JetBrains Mono", monospace; }

  /* -------- project detail slide -------- */
  .project-head { display: flex; justify-content: space-between; align-items: flex-start; gap: 16px; flex-wrap: wrap; }
  .project-head h2 { font-size: clamp(1.9rem, 1.5rem + 1.6vw, 2.6rem); max-width: 18ch; }
  .project-fields { display: flex; flex-direction: column; gap: 22px; max-width: 640px; }
  .field { display: flex; flex-direction: column; gap: 7px; }
  .field-label {
    font-family: "JetBrains Mono", monospace; font-size: 0.7rem; letter-spacing: 0.1em;
    text-transform: uppercase; color: color-mix(in srgb, var(--black) 48%, transparent);
  }
  .field p { font-size: 1.02rem; color: color-mix(in srgb, var(--black) 82%, transparent); }
  .project-links { display: flex; gap: 12px; flex-wrap: wrap; margin-top: 4px; }
  .project-links a {
    font-family: "JetBrains Mono", monospace; font-size: 0.82rem; color: var(--signal); text-decoration: none;
    padding: 8px 14px; border: 1px solid color-mix(in srgb, var(--signal) 35%, transparent); border-radius: 100px;
  }
  .project-links a:hover { background: color-mix(in srgb, var(--signal) 10%, transparent); }

  /* -------- OS slide -------- */
  .os-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 14px; }
  @media (max-width: 720px) { .os-grid { grid-template-columns: 1fr; } }
  .os-card { border: 1px solid var(--line); border-radius: 12px; padding: 22px; background: var(--card); }
  .os-card .tag { font-family: "JetBrains Mono", monospace; font-size: 0.68rem; letter-spacing: 0.1em; text-transform: uppercase; color: var(--signal); }
  .os-card h3 { margin-top: 6px; font-size: 1.15rem; }
  .os-card p { margin-top: 8px; font-size: 0.92rem; color: color-mix(in srgb, var(--black) 72%, transparent); }
  .os-split { display: flex; gap: 10px; margin-top: 14px; flex-wrap: wrap; }
  .os-split span {
    font-family: "JetBrains Mono", monospace;
    font-size: 0.7rem;
    padding: 3px 9px;
    border: 1px solid var(--line);
    border-radius: 100px;
    color: color-mix(in srgb, var(--black) 65%, transparent);
  }

  /* -------- links / close -------- */
  .link-list { display: flex; flex-direction: column; gap: 2px; border-top: 1px solid var(--line); }
  .link-row { display: flex; justify-content: space-between; align-items: baseline; gap: 20px; padding: 16px 0; border-bottom: 1px solid var(--line); }
  .link-row .name { font-size: 1rem; font-weight: 500; }
  .link-row .note { font-size: 0.82rem; color: color-mix(in srgb, var(--black) 60%, transparent); }
  .link-row a.url { font-family: "JetBrains Mono", monospace; font-size: 0.78rem; color: var(--signal); text-decoration: none; border-bottom: 1px solid color-mix(in srgb, var(--signal) 40%, transparent); white-space: nowrap; }

  .sig { font-size: 0.88rem; color: color-mix(in srgb, var(--black) 55%, transparent); }

  @media (prefers-reduced-motion: no-preference) {
    .slide-inner { animation: rise 0.5s var(--ease, cubic-bezier(0.22,1,0.36,1)) both; }
  }
  @keyframes rise { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
`;
